import React from 'react';
import { Icons as CarbonIcons } from '@carbon/react';

const Icons = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonIcons
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonIcons>
    );
};

Icons.defaultProps = {
    className: ''
};

export default Icons;
